    ),
  );
}

async function increase<ChainTypeT extends ChainType | string>(
  provider: EthereumProvider,
  networkHelpers: NetworkHelpers<ChainTypeT>,
  amountInSeconds: NumberLike,
): Promise<number> {
  const normalizedAmount = await toBigInt(amountInSeconds);
  const latestTimestamp = await toBigInt(await networkHelpers.time.latest());
  const targetTimestamp = latestTimestamp + normalizedAmount;

  await provider.request({
    method: "evm_setNextBlockTimestamp",
    params: [toRpcQuantity(targetTimestamp)],
  });

  await networkHelpers.mine();

  return await networkHelpers.time.latest();
}

public async compileBuildInfo(
  buildInfo: SolidityBuildInfo,
  options?: CompileBuildInfoOptions,
): Promise<CompilerOutput> {
  const quiet = options?.quiet ?? false;

  // Build info recompilation is always solc-only: build info files are
  // produced by solc and must be recompiled with the same solc version.
  // We bypass both downloadCompilers and getCompiler hooks — this is a
  // self-contained solc replay path, not plugin-configurable compilation.
  await downloadSolcCompilers(new Set([buildInfo.solcVersion]), quiet);

  const compiler = await getCompiler(buildInfo.solcVersion, {
    preferWasm: false,
  });

  return await compiler.compile(buildInfo.input);
}

function parseArgumentValue(
  value: string,
  type: ArgumentType,
  name: string,
): ArgumentValue {
  switch (type) {
    case ArgumentType.STRING_WITHOUT_DEFAULT:
    case ArgumentType.FILE_WITHOUT_DEFAULT:
    case ArgumentType.STRING:
    case ArgumentType.FILE:
      return value;
    case ArgumentType.INT:
      return validateAndParseInt(name, value);
    case ArgumentType.LEVEL:
      return validateAndParseLevel(name, value);
    case ArgumentType.FLOAT:
      return validateAndParseFloat(name, value);
    case ArgumentType.BIGINT:
      return validateAndParseBigInt(name, value);
    case ArgumentType.BOOLEAN:
      return validateAndParseBoolean(name, value);
    case ArgumentType.FLAG:
      return validateAndParseFlag(name, value);
  }
}

async function resolveUserConfig(
  userConfig: HardhatUserConfig,
  resolveConfigurationVariable: ConfigurationVariableResolver,
  next: (
    nextUserConfig: HardhatUserConfig,
    nextResolveConfigurationVariable: ConfigurationVariableResolver,
  ) => Promise<HardhatConfig>,
): Promise<HardhatConfig> {
  const resolvedConfig = await next(userConfig, resolveConfigurationVariable);

  return {
    ...resolvedConfig,
    verify: {
      ...resolvedConfig.verify,
      blockscout: resolveBlockscoutConfig(userConfig.verify?.blockscout),
      etherscan: resolveEtherscanConfig(
        userConfig.verify?.etherscan,
        resolveConfigurationVariable,
      ),
      sourcify: resolveSourcifyConfig(userConfig.verify?.sourcify),
    },
  };
}

async function getBalanceChanges(
  ethers: HardhatEthers,
  transaction: TransactionResponse | Promise<TransactionResponse>,
  accounts: Array<Addressable | string>,
  options?: BalanceChangeOptions,
): Promise<bigint[]> {
  const txResponse = await transaction;

  const txReceipt = await txResponse.wait();
  assertIsNotNull(
    txReceipt,
    "Transaction's receipt cannot be fetched from the network",
  );
  const txBlockNumber = txReceipt.blockNumber;

  const balancesAfter = await getBalances(ethers, accounts, txBlockNumber);
  const balancesBefore = await getBalances(ethers, accounts, txBlockNumber - 1);

  const txFees = await getTxFees(accounts, txResponse, options);

  return balancesAfter.map(
    (balance, ind) => balance + txFees[ind] - balancesBefore[ind],
  );
}

async #convertContractFutureToViemContract(
  connection: NetworkConnection<ChainTypeT>,
  future: ContractFuture<string>,
  deployedContract: { address: string },
) {
  switch (future.type) {
    case FutureType.NAMED_ARTIFACT_CONTRACT_DEPLOYMENT:
    case FutureType.NAMED_ARTIFACT_LIBRARY_DEPLOYMENT:
    case FutureType.NAMED_ARTIFACT_CONTRACT_AT:
      return await this.#convertHardhatContractToViemContract(
        connection,
        future,
        deployedContract,
      );
    case FutureType.CONTRACT_DEPLOYMENT:
    case FutureType.LIBRARY_DEPLOYMENT:
    case FutureType.CONTRACT_AT:
      return await this.#convertArtifactToViemContract(
        connection,
        future,
        deployedContract,
      );
  }
}

public compare(compilerOutputBytecode: CompilerOutputBytecode): boolean {
  const unlinkedExecutableSection = inferExecutableSection(
    compilerOutputBytecode.object,
  );

  // If the lengths differ, the bytecodes cannot match, so we can return early
  if (this.executableSection.length !== unlinkedExecutableSection.length) {
    return false;
  }

  const normalizedBytecode = nullifyBytecodeOffsets(
    this.executableSection,
    compilerOutputBytecode,
  );

  const normalizedUnlinkedBytecode = nullifyBytecodeOffsets(
    unlinkedExecutableSection,
    compilerOutputBytecode,
  );

  return normalizedBytecode === normalizedUnlinkedBytecode;
}

function nullifyBytecodeOffsets(
  bytecode: string,
  {
    object: unlinkedBytecode,
    linkReferences,
    immutableReferences,
  }: CompilerOutputBytecode,
): string {
  const dynamicOffsets = [
    ...getLibraryOffsets(linkReferences),
    ...getImmutableOffsets(immutableReferences),
    ...getCallProtectionOffsets(bytecode, unlinkedBytecode),
  ];

  const bytecodeChars = [...bytecode];
  for (const { start, length } of dynamicOffsets) {
    bytecodeChars.fill("0", start * 2, (start + length) * 2);
  }

  return bytecodeChars.join("");
}

async function createVerificationProviderInstance({
  provider,
  networkName,
  chainDescriptors,
  verificationProviderName,
  verificationProvidersConfig,
  dispatcher,
}: {
  provider: EthereumProvider;
  networkName: string;
  chainDescriptors: ChainDescriptorsConfig;
  verificationProviderName: keyof VerificationProvidersConfig;
  verificationProvidersConfig: VerificationProvidersConfig;
  dispatcher?: Dispatcher;
}): Promise<VerificationProvider> {
  const chainId = await getChainId(provider);

  const ProviderClass = VERIFICATION_PROVIDERS[verificationProviderName];

  const createOptions = await ProviderClass.resolveConfig({
    chainId,
    networkName,
    chainDescriptors,
    verificationProvidersConfig,
    dispatcher,
  });

  return await ProviderClass.create(createOptions);
}

async #handleRequest(request: JsonRpcRequest): Promise<JsonRpcResponse> {
  assertHardhatInvariant(
    this.#provider !== undefined,
    "The provider is not defined",
  );

  const stringifiedArgs = JSON.stringify(request);

  let edrResponse: Response;

  // We need to catch errors here, as the provider creation can panic unexpectedly,
  // and we want to make sure such a crash is propagated as a ProviderError.
  try {
    edrResponse = await this.#provider.handleRequest(stringifiedArgs);
  } catch (error) {
    ensureError(error);

    // eslint-disable-next-line no-restricted-syntax -- allow throwing UnknownError
    throw new UnknownError(error.message, error);
  }

  return await this.#handleEdrResponse(
    edrResponse,
    request.method,
    Array.isArray(request.params) ? request.params : undefined,
  );
}

public static async create<ChainTypeT extends ChainType | string>(
  id: number,
  networkName: string,
  chainType: ChainTypeT,
  networkConfig: NetworkConfig,
  closeConnection: CloseConnectionFunction<ChainTypeT>,
  createProvider: (
    networkConnection: NetworkConnectionImplementation<ChainTypeT>,
  ) => Promise<EthereumProvider>,
): Promise<NetworkConnectionImplementation<ChainTypeT>> {
  const networkConnection = new NetworkConnectionImplementation(
    id,
    networkName,
    chainType,
    networkConfig,
    closeConnection,
  );

  const provider = await createProvider(networkConnection);
  networkConnection.#setProvider(provider);
  return networkConnection;
}

public static async create(
  projectRootPath: string,
  remappingsReader: RemappingsReaderFunction = (
    packageName,
    packageVersion,
    packagePath,
    defaultBehavior,
  ) => defaultBehavior(packageName, packageVersion, packagePath),
): Promise<RemappedNpmPackagesGraphImplementation> {
  const projectPackageJson = await readJsonFile<PackageJson>(
    path.join(projectRootPath, "package.json"),
  );

  const resolvedNpmPackage: ResolvedNpmPackage = {
    name: projectPackageJson.name,
    version: projectPackageJson.version,
    exports: projectPackageJson.exports,
    rootFsPath: projectRootPath,
    inputSourceNameRoot: HARDHAT_PROJECT_INPUT_SOURCE_NAME_ROOT,
  };

  return new RemappedNpmPackagesGraphImplementation(
    resolvedNpmPackage,
    remappingsReader,
  );
}

async function isTelemetryEnabled(
  telemetryConfigFilePath?: string,
): Promise<boolean> {
  telemetryConfigFilePath ??= await getTelemetryConfigFilePath();

  log(`Looking for telemetry config file at ${telemetryConfigFilePath}`);

  if (await exists(telemetryConfigFilePath)) {
    // Telemetry enabled value was explicitly set, hence return the answer
    const { enabled } = await readJsonFile<TelemetryConfig>(
      telemetryConfigFilePath,
    );
    log(`Telemetry enabled value: ${enabled}`);

    return enabled;
  }

  log("No telemetry config file found, assuming telemetry is enabled");

  return true;
}

private static _getSerializedModulesInReverseTopologicalOrder(
  serializedIgnitionModule: SerializedIgnitionModule,
): SerializedModuleDescription[] {
  const graph: Graph<SerializedModuleDescription> = new Map();

  for (const mod of Object.values(serializedIgnitionModule.modules)) {
    graph.set(mod, new Set());
  }

  for (const mod of Object.values(serializedIgnitionModule.modules)) {
    for (const submodToken of mod.submodules) {
      const submod = serializedIgnitionModule.modules[submodToken.moduleId];
      graph.get(submod)!.add(mod);
    }
  }

  return getNodesInTopologicalOrder(graph);
}

