  private readonly _deploymentDirPath: string,
  private readonly _executionEventListener?:
    | ExecutionEventListener
    | undefined,
) {
  const artifactsDir = path.join(this._deploymentDirPath, "artifacts");
  const buildInfoDir = path.join(this._deploymentDirPath, "build-info");
  const journalPath = path.join(this._deploymentDirPath, "journal.jsonl");
  const deployedAddressesPath = path.join(
    this._deploymentDirPath,
    "deployed_addresses.json",
  );

  this._journal = new FileJournal(journalPath, this._executionEventListener);

  this._paths = {
    deploymentDir: this._deploymentDirPath,
    artifactsDir,
    buildInfoDir,
    journalPath,
    deployedAddressesPath,
  };

  this._deploymentDirsEnsured = false;
}

function decodeArtifactFunctionCallResult(
  artifact: Artifact,
  functionName: string,
  returnData: string,
): InvalidResultError | SuccessfulEvmExecutionResult {
  const validationErrors = validateArtifactFunctionName(artifact, functionName);

  if (validationErrors.length > 0) {
    throw validationErrors[0];
  }

  const iface = ethers.Interface.from(artifact.abi);
  const functionFragment = getFunctionFragment(iface, functionName);

  try {
    const decoded = iface.decodeFunctionResult(functionFragment, returnData);
    const values = ethersResultIntoEvmTuple(decoded, functionFragment.outputs);

    return { type: EvmExecutionResultTypes.SUCCESSFUL_RESULT, values };
  } catch {
    return {
      type: EvmExecutionResultTypes.INVALID_RESULT_ERROR,
      data: returnData,
    };
  }
}

private async _syncNonces(
  deploymentState: DeploymentState,
  ignitionModule: IgnitionModule<
    string,
    string,
    IgnitionModuleResult<string>
  >,
  accounts: string[],
  defaultSender: string,
): Promise<DeploymentState> {
  const nonceSyncMessages = await getNonceSyncMessages(
    this._jsonRpcClient,
    deploymentState,
    ignitionModule,
    accounts,
    defaultSender,
    this._requiredConfirmations,
  );

  for (const message of nonceSyncMessages) {
    deploymentState = await applyNewMessage(
      message,
      deploymentState,
      this._deploymentLoader,
    );
  }

  return deploymentState;
}

async function _storeArtifactAndBuildInfoAgainstDeployment(
  future:
    | NamedArtifactLibraryDeploymentFuture<string>
    | NamedArtifactContractDeploymentFuture<string>
    | NamedArtifactContractAtFuture<string>,
  {
    deploymentLoader,
    artifactResolver,
  }: {
    deploymentLoader: DeploymentLoader;
    artifactResolver: ArtifactResolver;
  },
): Promise<void> {
  const artifact = await artifactResolver.loadArtifact(future.contractName);
  await deploymentLoader.storeNamedArtifact(
    future.id,
    future.contractName,
    artifact,
  );
  const buildInfo = await artifactResolver.getBuildInfo(future.contractName);

  if (buildInfo !== undefined) {
    await deploymentLoader.storeBuildInfo(future.id, buildInfo);
  }
}

static async getAccountFromAddress(
    address: string,
    privateKey: string
): Promise<OpenZeppelinAccount> {
    const contractFactory = await this.getContractFactory();
    const contract = contractFactory.getContractAt(address);

    const { publicKey: expectedPubKey } = await contract.call("getPublicKey");
    const publicKey = ec.starkCurve.getStarkKey(privateKey);

    if (BigInt(publicKey) !== expectedPubKey) {
        throw new StarknetPluginError(
            "The provided private key is not compatible with the public key stored in the contract."
        );
    }

    return new this(contract, privateKey, undefined, true);
}

public async setGuardian(
    newGuardianPrivateKey?: string,
    invokeOptions?: InvokeOptions
): Promise<string> {
    let guardianPublicKey: string;
    if (!BigInt(newGuardianPrivateKey || 0)) {
        newGuardianPrivateKey = undefined;
        guardianPublicKey = undefined;
    } else {
        guardianPublicKey = ec.starkCurve.getStarkKey(newGuardianPrivateKey);
    }

    const call: CallParameters = {
        functionName: "changeGuardian",
        toContract: this.starknetContract,
        calldata: { newGuardian: BigInt(guardianPublicKey || 0) }
    };

    const txHash = await this.multiInvoke([call], invokeOptions);

    // set after signing
    this.guardianPrivateKey = newGuardianPrivateKey;
    this.guardianPublicKey = guardianPublicKey;

    return txHash;
}

private async compileChangedContracts(
    newCacheEntry: Record<string, ContractData>,
    changed: Set<string>
): Promise<void> {
    for (const changedContract of changed) {
        const entry = newCacheEntry[changedContract];
        const compileArguments: TaskArguments = {
            paths: [changedContract],
            disableHintValidation: entry?.disableHintValidation,
            accountContract: entry?.accountContract,
            cairoPath: entry?.cairoPath
        };

        await starknetDeprecatedCompileAction(compileArguments, this.hre);
    }
}

static getInstance(cliArgs: TaskArguments, hre: HardhatRuntimeEnvironment): ScarbWrapper {
    if (this.instance) {
        return this.instance;
    } else if (cliArgs.scarbCommand) {
        this.instance = new CustomScarbWrapper(cliArgs.scarbCommand);
    } else if (hre.config.starknet.scarbCommand) {
        this.instance = new CustomScarbWrapper(hre.config.starknet.scarbCommand);
    } else {
        this.instance = new DockerizedScarbWrapper(
            hre.config.starknet.dockerizedVersion,
            hre.config.paths.root
        );
    }
    return this.instance;
}

