#updateResolvedPromiseCache(
  key: string,
  promise: Promise<SharedPromiseExecutionResult<ValueT>>,
  result: SharedPromiseExecutionResult<ValueT>,
): void {
  // We only update the cache if the cached promise is still the one that got
  // resolved, which may not always be the case. The reason is that the
  // resolved promise may have been deleted and/or replaced in the cache.
  if (this.#cache.get(key) === promise) {
    if (result.success) {
      this.#cache.set(key, { success: true, value: result.value });
    } else {
      this.#cache.delete(key);
    }
  }
}

import {deployScript, artifacts} from '../rocketh/deploy.js';

export default deployScript(
	// this allow us to define a functiong which takes as first argument an environment object
	async ({deployViaProxy, namedAccounts}) => {
		// you can get named accounts from the environment object
		const {deployer, admin} = namedAccounts;

		const prefix = 'proxy:';
		// you can use the deployViaProxy function to deploy a contract via a proxy
		await deployViaProxy(
			'GreetingsRegistry',
			{
				account: deployer,
				artifact: artifacts.GreetingsRegistry,
				args: [prefix],
			},
			{
				owner: admin,
				linkedData: {
					prefix,
					admin,
				},
			},
		);
	},
	// finally you can pass tags and dependencies
	{tags: ['GreetingsRegistry', 'GreetingsRegistry_deploy']},
);

async #toViemContracts<
    ModuleIdT extends string,
    ContractNameT extends string,
    IgnitionModuleResultsT extends IgnitionModuleResult<ContractNameT>,
  >(
    connection: NetworkConnection<ChainTypeT>,
    ignitionModule: IgnitionModule<
      ModuleIdT,
      ContractNameT,
      IgnitionModuleResultsT
    >,
    result: SuccessfulDeploymentResult,
  ): Promise<
    IgnitionModuleResultsToViemContracts<ContractNameT, IgnitionModuleResultsT>
  > {
    return Object.fromEntries(
      await Promise.all(
        Object.entries(ignitionModule.results).map(
          async ([name, contractFuture]) => [
            name,
            await this.#getContract(
              connection,
              contractFuture,
              result.contracts[contractFuture.id],
            ),
          ],
        ),
      ),
    );
  }

function formatProjectRootResolutionError(
  error: ProjectRootResolutionError,
): string {
  switch (error.type) {
    case RootResolutionErrorType.PROJECT_ROOT_FILE_NOT_IN_PROJECT: {
      return `The file is not inside your Hardhat project.`;
    }

    case RootResolutionErrorType.PROJECT_ROOT_FILE_DOES_NOT_EXIST: {
      return "The file doesn't exist";
    }

    case RootResolutionErrorType.PROJECT_ROOT_FILE_IN_NODE_MODULES: {
      // TODO: This should have a link to the docs.
      return `The file is inside your node_modules directory.

Please read Hardhat's documentation to learn how to compile npm files.`;
    }
  }
}

export function setupHardhatDeploy<
	Extensions extends Record<string, (env: Environment<any, any, any>) => any> = {},
	NamedAccounts extends UnresolvedUnknownNamedAccounts = UnresolvedUnknownNamedAccounts,
	Data extends UnresolvedNetworkSpecificData = UnresolvedNetworkSpecificData,
>(extensions: Extensions) {
	async function loadEnvironmentFromHardhatWithExtensions(
		required: {hre: HardhatRuntimeEnvironment; connection?: NetworkConnection},
		// options?: {
		// 	useChainIdOfForkedNetwork?: boolean;
		// }
	) {
		const env = await loadEnvironmentFromHardhat<NamedAccounts, Data>(required);
		return enhanceEnvIfNeeded<Extensions, NamedAccounts, Data>(env, extensions);
	}

	return {
		loadEnvironmentFromHardhat: loadEnvironmentFromHardhatWithExtensions,
	};
}

